// Storage Account with ZRS
resource storageAccount 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: 'mystorageacct'
  location: location
  sku: {
    name: 'Standard_ZRS'   // Zone-Redundant Storage
  }
  kind: 'StorageV2'
  properties: {
    minimumTlsVersion: 'TLS1_2'
    supportsHttpsTrafficOnly: true
  }
}

// SQL Database with zone-redundant HA
resource sqlDatabase 'Microsoft.Sql/servers/databases@2022-05-01-preview' = {
  name: '${sqlServer.name}/mydb'
  location: location
  sku: {
    name: 'BC_Gen5'
    tier: 'BusinessCritical'
    capacity: 8
  }
  properties: {
    zoneRedundant: true   // Enable cross-zone HA replicas
  }
}

// Standard LB with zone-redundant frontend IP (no zones property = zone-redundant)
resource publicIp 'Microsoft.Network/publicIPAddresses@2023-04-01' = {
  name: 'myPublicIP'
  location: location
  sku: { name: 'Standard' }
  properties: {
    publicIPAllocationMethod: 'Static'
    // zones property omitted -> platform makes it zone-redundant
  }
}
